const listSemesters = `-- name: ListSemesters :many
SELECT id, tenant_id, name, start_date, end_date, is_current, created_at, updated_at, deleted_at FROM semester
WHERE deleted_at IS NULL
ORDER BY start_date DESC, id DESC
`

func (q *Queries) ListSemesters(ctx context.Context) ([]Semester, error) {
	rows, err := q.db.Query(ctx, listSemesters)
	if err != nil {
		return nil, err
	}
	defer rows.Close()
	items := []Semester{}
	for rows.Next() {
		var i Semester
		if err := rows.Scan(
			&i.ID,
			&i.TenantID,
			&i.Name,
			&i.StartDate,
			&i.EndDate,
			&i.IsCurrent,
			&i.CreatedAt,
			&i.UpdatedAt,
			&i.DeletedAt,
		); err != nil {
			return nil, err
		}
		items = append(items, i)
	}
	if err := rows.Err(); err != nil {
		return nil, err
	}
	return items, nil
}

